codeComparison.new:
/* Light theme */
:root {
  --primary: #667eea;
  --bg: #f9f9f9;
  --card-bg: #ffffff;
  --text: #333;
}

/* Dark theme */
[data-theme="dark"] {
  --primary: #8b9de8;
  --bg: #1a1a1a;
  --card-bg: #2a2a2a;
  --text: #f0f0f0;
}

/* Same CSS, different look! */
.card { background: var(--card-bg); }
.button { background: var(--primary); }
h1 { color: var(--primary); }

codeComparison.old:
