codeComparison.new:
/* 3D card flip */
.card-container {
  perspective: 1000px;
}
.card-flip {
  transform-style: preserve-3d;
  transition: transform 0.6s;
}
.card-container:hover .card-flip {
  transform: rotateY(180deg);
}
.card-front, .card-back {
  backface-visibility: hidden;
}
.card-back {
  transform: rotateY(180deg);
}

